SELECT "user", COUNT(*) AS total_clicks FROM (SELECT "user" FROM "ECLIPSE_MEGAMOVIE"."ECLIPSE_MEGAMOVIE"."PHOTOS_V_0_1" UNION ALL SELECT "user" FROM "ECLIPSE_MEGAMOVIE"."ECLIPSE_MEGAMOVIE"."PHOTOS_V_0_2" UNION ALL SELECT "user" FROM "ECLIPSE_MEGAMOVIE"."ECLIPSE_MEGAMOVIE"."PHOTOS_V_0_3") AS all_photos GROUP BY "user" ORDER BY total_clicks DESC LIMIT 1